12: const Diacritic = enum(u8) {
13:     empty, // nguyên âm, không dấu.
14:     circumflex, // dấu nón: â, ô, ê.
15:     horn, // dấu móc: ư, ơ.
16:     breve, // dấu ă.
17:     bar, // dấu gạch: đ.
18: };
19: 
20: const Tone = enum(u8) {
21:     level, // thanh ngang, không dấu.
22:     rising, // sắc.
23:     falling, // huyền.
24:     dipping_rising, // hỏi.
25:     rising_glottalized, // ngã.
26:     falling_glottalized, // nặng.
27: };
